import React, { useState } from 'react';

function Contact({ data }) {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const mailtoLink = `mailto:${data.email}?subject=Portfolio Inquiry from ${formData.name}&body=${encodeURIComponent(formData.message)}`;
    window.location.href = mailtoLink;
    setFormData({ name: '', email: '', message: '' });
  };

  if (!data) return null;

  return (
    <section id="contact" className="py-12 md:py-16 bg-gray-50">
      <div className="max-w-2xl mx-auto px-4">
        <div className="bg-white rounded-2xl shadow-lg p-8">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Contact</h2>
          
          <div className="space-y-4 mb-8">
            <a href={`mailto:${data.email}`} className="flex items-center gap-4 p-4 rounded-lg border border-gray-200 hover:bg-gray-50 transition">
              <span className="text-2xl">✉️</span>
              <div>
                <p className="text-xs text-gray-500 font-semibold">EMAIL</p>
                <p className="text-gray-900 font-semibold">{data.email}</p>
              </div>
            </a>
            <a href={`tel:${data.phone}`} className="flex items-center gap-4 p-4 rounded-lg border border-gray-200 hover:bg-gray-50 transition">
              <span className="text-2xl">📱</span>
              <div>
                <p className="text-xs text-gray-500 font-semibold">PHONE</p>
                <p className="text-gray-900 font-semibold">{data.phone}</p>
              </div>
            </a>
            <a href={data.linkedin} target="_blank" rel="noopener noreferrer" className="flex items-center gap-4 p-4 rounded-lg border border-gray-200 hover:bg-gray-50 transition">
              <span className="text-2xl">💼</span>
              <div>
                <p className="text-xs text-gray-500 font-semibold">LINKEDIN</p>
                <p className="text-gray-900 font-semibold">Connect on LinkedIn</p>
              </div>
            </a>
          </div>

          <div className="border-t border-gray-200 pt-8">
            <h3 className="text-lg font-bold text-gray-900 mb-4">Send me a message</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">Name</label>
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600"
                  placeholder="Your Name"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">Email</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600"
                  placeholder="your@email.com"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">Message</label>
                <textarea
                  name="message"
                  value={formData.message}
                  onChange={handleChange}
                  required
                  rows="4"
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600"
                  placeholder="Your message here..."
                ></textarea>
              </div>
              <button
                type="submit"
                className="w-full bg-gray-900 text-white font-semibold py-3 rounded-full hover:bg-gray-800 transition"
              >
                ✉️ Send Message
              </button>
            </form>
          </div>
        </div>
      </div>
    </section>
  );
}

export default Contact;
